        <NodeView node={currentNode} parentNode={parentNode} projectState={project} onSelectNode={(id) => { setProject(prev => ({ ...prev, currentNodeId: id })); setEditingNodeId(null); }} onRegenerate={(txt) => { setInput(txt); setEditingNodeId(currentNode.id); }} onSynthesize={(topic) => handleSubmit(topic, 'synthesize')} onRefresh={() => handleSubmit(undefined, 'refresh')} onMindmapNodeClick={(n) => handleSubmit(`Expand: ${n.label}`, 'branch')} onDeleteChatMessage={(i) => setProject(prev => { const node = prev.nodes[prev.currentNodeId]; if (!node?.chat) return prev; const newChat = [...node.chat]; newChat.splice(i, 1); return { ...prev, nodes: { ...prev.nodes, [prev.currentNodeId]: { ...node, chat: newChat } } } }; })} onDeleteWidget={(nodeId, idx) => setWidgetToDelete({ nodeId, idx })} onToggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} isSidebarOpen={isSidebarOpen} onUpdateNodeData={(nid, data) => setProject(prev => { const node = prev.nodes[nid]; if (!node) return prev; return { ...prev, nodes: { ...prev.nodes, [nid]: { ...node, data: { ...node.data, ...data } } } }; })} onRevertState={(i) => setProject(prev => { const node = prev.nodes[prev.currentNodeId]; if (!node?.chat[i]?.dataSnapshot) return prev; const target = node.chat[i]; return { ...prev, nodes: { ...prev.nodes, [prev.currentNodeId]: { ...node, chat: node.chat.slice(0, i + 1), data: JSON.parse(JSON.stringify(target.dataSnapshot)), visualization: JSON.parse(JSON.stringify(target.visualizationSnapshot)), isLoading: false, processingStage: 'idle' } } }; })} onShowCleanupModal={() => setShowCleanupModal(true)} onUndoCleanup={() => setProject(prev => { const node = prev.nodes[prev.currentNodeId]; if (!node?.restorePoint) return prev; return { ...prev, nodes: { ...prev.nodes, [node.id]: { ...node, chat: node.restorePoint.chat, data: node.restorePoint.data, visualization: node.restorePoint.visualization, userInput: node.restorePoint.userInput, restorePoint: undefined } } }; })} />
        <ChatInput input={input} setInput={setInput} attachments={attachments} setAttachments={setAttachments} isProcessing={isProcessing} onSubmit={handleSubmit} onStop={() => abortControllerRef.current?.abort()} editingNodeId={editingNodeId} onPaste={handlePaste} />
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { ProjectNode, ProjectState, MindmapNode, NodeVisualization, NodeData } from '../types';
import { WidgetRenderer } from './GenerativeUI/WidgetRenderer';
import { DebugOverlay } from './DebugOverlay';
import { ChatTurn } from './ChatTurn';
import { ProjectKnowledgeCard } from './ProjectKnowledgeCard';
import { DataStoreExplorer } from './DataStoreExplorer';
import { SynthesisModal } from './SynthesisModal';
import { ConfirmationModal } from './ConfirmationModal';
import { NodeHeader } from './Layout/NodeHeader';
import { SnapshotBanner } from './Layout/SnapshotBanner';

interface NodeViewProps {
  node: ProjectNode;
  parentNode?: ProjectNode;
  projectState: ProjectState;
  onSelectNode: (id: string) => void;
  onRegenerate: (input: string) => void;
  onSynthesize: (topic?: string) => void;
  onRefresh: () => void;
  onMindmapNodeClick?: (node: MindmapNode) => void;
  onDeleteChatMessage?: (index: number) => void;
  onDeleteWidget: (nodeId: string, index: number) => void;
  onToggleSidebar: () => void;
  isSidebarOpen: boolean;
  onUpdateNodeData: (nodeId: string, data: any) => void;
  onRevertState: (index: number) => void;
  onShowCleanupModal: () => void;
  onUndoCleanup?: () => void;
}

export const NodeView: React.FC<NodeViewProps> = ({ 
  node, 
  parentNode, 
  projectState, 
  onSelectNode, 
  onRegenerate, 
  onSynthesize, 
  onRefresh,
  onMindmapNodeClick,
  onDeleteChatMessage,
  onDeleteWidget,
  onToggleSidebar,
  isSidebarOpen,
  onUpdateNodeData,
  onRevertState,
  onShowCleanupModal,
  onUndoCleanup
}) => {
  const [selectedImage, setSelectedImage] = useState<{data: string, name: string} | null>(null);
  const [showDebug, setShowDebug] = useState(false);
  const [showDataExplorer, setShowDataExplorer] = useState(false);
  const [showSynthesisModal, setShowSynthesisModal] = useState(false);
  const [vizMode, setVizMode] = useState<'minimized' | 'normal' | 'large' | 'maximized'>('normal');
  const [showVizDetails, setShowVizDetails] = useState(true);
  const scrollEndRef = useRef<HTMLDivElement>(null);

  const [viewingSnapshot, setViewingSnapshot] = useState<{data: NodeData, viz: NodeVisualization, index: number} | null>(null);
  const [confirmRevertIndex, setConfirmRevertIndex] = useState<number | null>(null);

  useEffect(() => {
    setViewingSnapshot(null);
    setConfirmRevertIndex(null);
  }, [node.id]);

  useEffect(() => {
    scrollEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [node.chat, node.isLoading, node.id, node.processingStage, viewingSnapshot]);

  const allNodes = (Object.values(projectState.nodes) as ProjectNode[]).sort((a, b) => a.timestamp - b.timestamp);
  const currentIndex = allNodes.findIndex(n => n.id === node.id);

  const handleDownload = (data: string, filename: string) => {
    const link = document.createElement('a');
    link.href = data;
    link.download = filename;
    link.click();
  };

  const hasDebugError = !!node.debugInfo?.error;

  const getVizHeight = () => {
     switch(vizMode) {
         case 'minimized': return '48px';
         case 'normal': return '45%';
         case 'large': return '75%';
         case 'maximized': return '100%';
     }
  };

  const VizControl: React.FC<{ 
    mode: typeof vizMode, 
    label: string, 
    icon: React.ReactNode, 
    isActive: boolean 
  }> = ({ mode, label, icon, isActive }) => (
    <button
        onClick={(e) => { e.stopPropagation(); setVizMode(mode); }}
        className={`p-1.5 rounded-lg transition-all ${isActive ? 'bg-indigo-100 text-indigo-600' : 'text-slate-400 hover:text-slate-600 hover:bg-slate-100'}`}
        title={label}
    >
        {icon}
    </button>
  );

  const isMaximized = vizMode === 'maximized' || vizMode === 'large';
  const isFullscreen = vizMode === 'maximized';

  const activeData = viewingSnapshot ? viewingSnapshot.data : node.data;
  const activeViz = viewingSnapshot ? viewingSnapshot.viz : node.visualization;
  const activeProjectData = activeData?.projectData;

  const snapshotIndices = node.chat
    .map((m, i) => (m.visualizationSnapshot && m.dataSnapshot ? i : -1))
    .filter(i => i !== -1);

  const currentSnapshotIndexInList = viewingSnapshot ? snapshotIndices.indexOf(viewingSnapshot.index) : -1;
  const hasPrevSnapshot = viewingSnapshot ? currentSnapshotIndexInList > 0 : snapshotIndices.length > 0;
  const hasNextSnapshot = viewingSnapshot ? true : false;

  const loadSnapshot = (index: number) => {
      const msg = node.chat[index];
      if (msg && msg.visualizationSnapshot && msg.dataSnapshot) {
          setViewingSnapshot({
              viz: msg.visualizationSnapshot,
              data: msg.dataSnapshot,
              index: index
          });
      }
  };

  const handlePrevSnapshot = () => {
    if (!viewingSnapshot) {
        const last = snapshotIndices[snapshotIndices.length - 1];
        if (last !== undefined) loadSnapshot(last);
        return;
    }
    if (currentSnapshotIndexInList > 0) {
        loadSnapshot(snapshotIndices[currentSnapshotIndexInList - 1]);
    }
  };

  const handleNextSnapshot = () => {
     if (!viewingSnapshot) return;
     if (currentSnapshotIndexInList < snapshotIndices.length - 1) {
         loadSnapshot(snapshotIndices[currentSnapshotIndexInList + 1]);
     } else {
         setViewingSnapshot(null);
     }
  };

  const getLoadingText = () => {
      switch(node.processingStage) {
          case 'analyzing': return 'Analyzing project requirements...';
          case 'updating_data': return 'Updating database & schemas...';
          case 'designing_ui': return 'Designing interface components...';
          case 'rendering': return 'Rendering visualizations...';
          default: return 'Gemini is thinking...';
      }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 relative pb-[110px]">
      <ConfirmationModal 
        isOpen={confirmRevertIndex !== null}
        onConfirm={() => {
            const idx = confirmRevertIndex!;
            setViewingSnapshot(null);
            setTimeout(() => onRevertState(idx), 0);
            setConfirmRevertIndex(null);
        }}
        onCancel={() => setConfirmRevertIndex(null)}
        title="Restore History State"
        message="Are you sure you want to revert to this state? All chat history, data, and visualizations created after this point will be permanently lost."
      />

      <NodeHeader 
        node={node} parentNode={parentNode} allNodes={allNodes} currentIndex={currentIndex}
        isSidebarOpen={isSidebarOpen} onToggleSidebar={onToggleSidebar} onSelectNode={onSelectNode}
        onShowDebug={() => setShowDebug(true)} onShowDataExplorer={() => setShowDataExplorer(true)}
        onRegenerate={() => onRegenerate(node.userInput)} onRefresh={onRefresh}
        onShowSynthesisModal={() => setShowSynthesisModal(true)} onShowCleanupModal={onShowCleanupModal}
        onUndoCleanup={onUndoCleanup} hasDebugError={hasDebugError}
        activeProjectDataLength={activeProjectData?.stores?.length || 0}
      />

      {viewingSnapshot && (
        <SnapshotBanner 
          currentIndex={viewingSnapshot.index} totalSteps={node.chat.length}
          hasPrevSnapshot={hasPrevSnapshot} hasNextSnapshot={hasNextSnapshot}
          onPrevSnapshot={handlePrevSnapshot} onNextSnapshot={handleNextSnapshot}
          onRevert={() => setConfirmRevertIndex(viewingSnapshot.index)}
          onExit={() => setViewingSnapshot(null)}
        />
      )}

      <div className="flex-1 relative overflow-hidden">
        <div 
            className="absolute top-0 left-0 right-0 overflow-y-auto bg-slate-50/50 px-4 pt-6 transition-all duration-300 ease-in-out"
            style={{ bottom: getVizHeight() }}
        >
            <div className="max-w-4xl mx-auto space-y-4 min-h-full pb-10">
                <ChatTurn 
                    message={{ 
                      role: 'user', 
                      text: node.userInput, 
                      timestamp: node.timestamp, 
                      attachments: node.userAttachments
                    }} 
                    onMindmapNodeClick={onMindmapNodeClick} 
                    isDeletable={false}
                    onImageClick={setSelectedImage}
                />

                {(viewingSnapshot ? node.chat.slice(0, viewingSnapshot.index + 1) : node.chat).map((msg, i) => (
                    <ChatTurn 
                        key={`${node.id}-msg-${i}`} 
                        message={msg} 
                        onMindmapNodeClick={onMindmapNodeClick}
                        isDeletable={true}
                        onDelete={() => onDeleteChatMessage?.(i)}
                        onImageClick={setSelectedImage}
                        onViewSnapshot={() => {
                            if (viewingSnapshot?.index === i) setViewingSnapshot(null);
                            else if (msg.visualizationSnapshot && msg.dataSnapshot) {
                                setViewingSnapshot({ viz: msg.visualizationSnapshot, data: msg.dataSnapshot, index: i });
                            }
                        }}
                        isViewingSnapshot={viewingSnapshot?.index === i}
                    />
                ))}

                {!viewingSnapshot && node.isLoading && (
                    <div className="flex justify-start pl-4 py-4">
                        <div className="bg-white px-4 py-2 rounded-2xl rounded-bl-none border border-slate-200 shadow-sm flex items-center gap-3">
                            <div className="relative w-4 h-4">
                                <div className="absolute top-0 left-0 w-full h-full border-2 border-indigo-200 rounded-full"></div>
                                <div className="absolute top-0 left-0 w-full h-full border-2 border-indigo-500 rounded-full border-t-transparent animate-spin"></div>
                            </div>
                            <span className="text-[10px] font-black text-slate-500 animate-pulse uppercase tracking-widest ml-1">{getLoadingText()}</span>
                        </div>
                    </div>
                )}
                <div ref={scrollEndRef} className="h-4"></div>
            </div>
        </div>

        <div 
            className={`absolute bottom-0 left-0 right-0 bg-white shadow-[0_-4px_30px_-10px_rgba(0,0,0,0.15)] border-t border-slate-200 transition-all duration-300 ease-in-out flex flex-col z-20 ${viewingSnapshot ? 'border-t-4 border-indigo-500' : ''}`}
            style={{ height: getVizHeight() }}
        >
            <div 
                className="h-12 shrink-0 border-b border-slate-100 flex items-center justify-between px-4 bg-slate-50/50 cursor-pointer hover:bg-slate-50 transition-colors"
                onClick={() => setVizMode(m => m === 'minimized' ? 'normal' : 'minimized')}
            >
                <div className="flex items-center gap-3">
                    <div className={`p-1.5 rounded-md ${viewingSnapshot ? 'bg-indigo-600 text-white' : 'bg-indigo-100 text-indigo-600'}`}>
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>
                    </div>
                    <div>
                        <div className="font-black text-[10px] uppercase tracking-widest text-slate-500">
                             {viewingSnapshot ? `History Mode (Step ${viewingSnapshot.index + 1})` : 'Visualization Deck'}
                        </div>
                        <div className="text-[10px] font-bold text-slate-400 leading-none truncate max-w-[200px]">
                            {activeViz?.title || 'Generative Output'}
                        </div>
                    </div>
                </div>

                <div className="flex items-center gap-2" onClick={e => e.stopPropagation()}>
                    <button 
                        onClick={() => setShowVizDetails(!showVizDetails)}
                        className={`p-1.5 rounded-lg border transition-all ${showVizDetails ? 'bg-indigo-50 border-indigo-200 text-indigo-600' : 'bg-white border-slate-200 text-slate-400'}`}
                    >
                         <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" /></svg>
                    </button>
                    <div className="w-px h-4 bg-slate-200 mx-1"></div>
                    <div className="flex items-center gap-1 bg-white border border-slate-200 rounded-xl p-1 shadow-sm">
                        <VizControl mode="minimized" label="Minimize" isActive={vizMode === 'minimized'} icon={<svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M20 12H4" /></svg>} />
                        <VizControl mode="normal" label="Normal View" isActive={vizMode === 'normal'} icon={<svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><rect x="3" y="3" width="18" height="18" rx="2" strokeWidth={3} /></svg>} />
                        <VizControl mode="large" label="Expanded View" isActive={vizMode === 'large'} icon={<svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 10l7-7m0 0l7 7m-7-7v18" /></svg>} />
                        <VizControl mode="maximized" label="Fullscreen" isActive={vizMode === 'maximized'} icon={<svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" /></svg>} />
                    </div>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto bg-slate-50/30 p-8 space-y-8">
                 <div className={`grid grid-cols-1 gap-6 transition-all duration-300 ${!showVizDetails ? 'grid-cols-1' : (isFullscreen ? 'lg:grid-cols-4' : 'lg:grid-cols-3')}`}>
                    {showVizDetails && (
                        <div className={`space-y-6 ${isFullscreen ? 'lg:col-span-1' : 'lg:col-span-1'}`}>
                            <div className="bg-white rounded-2xl p-5 border border-slate-200 shadow-sm hover:shadow-md transition-all">
                                <div className="flex items-center gap-2 mb-3">
                                    <div className="p-1.5 bg-emerald-100 text-emerald-600 rounded-lg"><svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg></div>
                                    <h2 className="text-[10px] font-black uppercase tracking-widest text-slate-500">Summary</h2>
                                </div>
                                <p className="text-xs font-medium text-slate-600 leading-relaxed">{activeData?.summary || "No summary available."}</p>
                            </div>

                            {activeData?.projectKnowledge && Object.keys(activeData.projectKnowledge).length > 0 && <ProjectKnowledgeCard knowledge={activeData.projectKnowledge} onSync={onRefresh} />}

                            <div className="bg-white rounded-2xl p-5 border border-slate-200 shadow-sm hover:shadow-md transition-all">
                                <div className="flex items-center gap-2 mb-3">
                                    <div className="p-1.5 bg-blue-100 text-blue-600 rounded-lg"><svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2H2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01" /></svg></div>
                                    <h2 className="text-[10px] font-black uppercase tracking-widest text-slate-500">Key Facts</h2>
                                </div>
                                <ul className="space-y-2">
                                    {activeData?.keyPoints?.map((kp, i) => (<li key={i} className="flex gap-2.5 text-xs text-slate-600"><span className="text-blue-400 font-bold mt-0.5">•</span><span className="leading-snug">{kp}</span></li>))}
                                </ul>
                            </div>
                        </div>
                    )}

                    <div className={`space-y-6 transition-all duration-300 ${!showVizDetails ? 'col-span-1' : (isFullscreen ? 'lg:col-span-3' : 'lg:col-span-2')}`}>
                        {activeViz?.widgets && activeViz.widgets.length > 0 ? (
                            activeViz.widgets.map((widget, idx) => (
                                <div key={`viz-${node.id}-${idx}`} className="relative group/widget">
                                    <WidgetRenderer widget={widget} onMindmapNodeClick={onMindmapNodeClick} isExpanded={isMaximized} projectData={activeProjectData} />
                                    <button onClick={(e) => { e.stopPropagation(); onDeleteWidget(node.id, idx); }} className="absolute top-4 right-4 z-40 p-2 bg-white text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl shadow-md border border-slate-200 opacity-0 group-hover/widget:opacity-100 transition-all transform scale-90 group-hover/widget:scale-100"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                                </div>
                            ))
                        ) : (
                            <div className="h-48 flex flex-col items-center justify-center border-2 border-dashed border-slate-200 rounded-2xl bg-slate-50/50 text-slate-400">
                                <svg className="w-8 h-8 mb-2 opacity-30" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                                <span className="text-[10px] font-bold uppercase tracking-widest opacity-60">No Visual Elements Generated</span>
                            </div>
                        )}
                    </div>
                 </div>
                 <div className="h-20"></div>
            </div>
        </div>
      </div>

      {selectedImage && (
          <div className="fixed inset-0 z-[60] flex items-center justify-center p-8 bg-slate-900/90 backdrop-blur-md" onClick={() => setSelectedImage(null)}>
              <div className="relative max-w-6xl max-h-full flex flex-col items-center gap-6" onClick={e => e.stopPropagation()}>
                  <img src={selectedImage.data} className="rounded-3xl shadow-2xl max-h-[80vh] object-contain border border-white/20" />
                  <div className="flex gap-4">
                      <button onClick={() => handleDownload(selectedImage.data, selectedImage.name)} className="px-8 py-3 bg-indigo-600 text-white rounded-2xl font-black flex items-center gap-2 hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-500/20">Download</button>
                      <button onClick={() => setSelectedImage(null)} className="px-8 py-3 bg-white/10 text-white rounded-2xl font-black border border-white/20 hover:bg-white/20 transition-all backdrop-blur-md">Close</button>
                  </div>
              </div>
          </div>
      )}

      {showDebug && <DebugOverlay debugInfo={node.debugInfo} onClose={() => setShowDebug(false)} />}

      {showDataExplorer && activeProjectData && (
        <DataStoreExplorer stores={activeProjectData.stores} onClose={() => setShowDataExplorer(false)} onUpdateStores={(newStores) => onUpdateNodeData(node.id, { projectData: { stores: newStores } })} />
      )}

      <SynthesisModal isOpen={showSynthesisModal} onConfirm={(topic) => { setShowSynthesisModal(false); onSynthesize(topic); }} onCancel={() => setShowSynthesisModal(false)} />
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Sidebar } from './components/Sidebar';
import { NodeView } from './components/NodeView';
import { ChatInput } from './components/Layout/ChatInput';
import { ProjectNode, ProjectState, ThinkingBudgetLevel, NodeData, ModelProvider, CustomModelConfig, RestorePoint } from './types';
import { generateNodeResponse } from './services/api';
import { ConfirmationModal } from './components/ConfirmationModal';
import { CleanupModal } from './components/CleanupModal';
import { deepMerge } from './utils/helpers';

const INITIAL_ROOT_ID = 'root-1';

const DEFAULT_STATE: ProjectState = {
  rootId: INITIAL_ROOT_ID,
  currentNodeId: INITIAL_ROOT_ID,
  selectedModel: 'gemini-3-pro-preview',
  thinkingBudget: 'low',
  isGroundingEnabled: false,
  modelProvider: 'gemini',
  customModelConfig: { endpoint: 'http://localhost:11434/v1/chat/completions', modelName: 'llama3', apiKey: '' },
  nodes: {
    [INITIAL_ROOT_ID]: {
      id: INITIAL_ROOT_ID, parentId: null, timestamp: Date.now(), userInput: "Project Start: Initialize environment.", userAttachments: [], children: [], isLoading: false, processingStage: 'idle',
      data: { summary: "Project workspace initialized. Ready for planning.", keyPoints: ["Workspace created"], projectKnowledge: {}, projectData: { stores: [] } },
      visualization: { title: "Workspace Root", widgets: [] }, chat: [] 
    }
  }
};

const STORAGE_KEY = 'gemini_project_mind_db_v10';

const App: React.FC = () => {
  const [project, setProject] = useState<ProjectState>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (!saved) return DEFAULT_STATE;
      const parsed = JSON.parse(saved);
      if (parsed.nodes) {
        Object.keys(parsed.nodes).forEach(key => {
            const node = parsed.nodes[key];
            if (node.isLoading) {
                node.isLoading = false;
                node.processingStage = 'idle';
                if (!node.chat) node.chat = [];
                node.chat.push({ role: 'assistant', text: '⚠️ Generation was interrupted.', timestamp: Date.now() });
            }
            if (!node.data.projectData) node.data.projectData = { stores: [] };
        });
      }
      return parsed;
    } catch (e) { return DEFAULT_STATE; }
  });

  const [input, setInput] = useState('');
  const [editingNodeId, setEditingNodeId] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [attachments, setAttachments] = useState<{name: string, type: string, data: string}[]>([]);
  const [confirmDelete, setConfirmDelete] = useState<{ id: string } | null>(null);
  const [widgetToDelete, setWidgetToDelete] = useState<{nodeId: string, idx: number} | null>(null);
  const [showCleanupModal, setShowCleanupModal] = useState(false);
  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => { localStorage.setItem(STORAGE_KEY, JSON.stringify(project)); }, [project]);

  const currentNode = project.nodes[project.currentNodeId] || project.nodes[project.rootId];
  const parentNode = currentNode?.parentId ? project.nodes[currentNode.parentId] : undefined;

  const handleSubmit = async (overrideInput?: string, subMode: 'branch' | 'chat' | 'synthesize' | 'refresh' | 'cleanup' = 'branch') => {
    const finalInput = overrideInput ?? input;
    if (isProcessing) return;
    // Allow empty input for cleanup and refresh/synthesize modes
    if (subMode !== 'synthesize' && subMode !== 'refresh' && subMode !== 'cleanup' && !finalInput.trim() && attachments.length === 0) return;

    setIsProcessing(true);
    if (abortControllerRef.current) abortControllerRef.current.abort();
    const controller = new AbortController();
    abortControllerRef.current = controller;

    const currentAttachments = [...attachments];
    // Cleanup is now a branching operation (new node) to preserve history
    const targetNodeId = (subMode === 'chat' || subMode === 'refresh' || (!!editingNodeId && subMode !== 'cleanup')) ? project.currentNodeId : uuidv4();

    if (!overrideInput) setInput('');
    setAttachments([]);
    setEditingNodeId(null);

    let updatedProject: ProjectState;
    const timestamp = Date.now();

    if (subMode === 'chat' || subMode === 'refresh' || project.currentNodeId === targetNodeId) {
      const node = project.nodes[targetNodeId];
      const newChat = [...(node.chat || [])];
      if (subMode === 'chat') newChat.push({ role: 'user', text: finalInput, timestamp, attachments: currentAttachments.length > 0 ? currentAttachments : undefined });
      updatedProject = { ...project, nodes: { ...project.nodes, [targetNodeId]: { ...node, chat: newChat, isLoading: true, processingStage: 'analyzing' } } };
    } else {
      const parent = project.nodes[project.currentNodeId];
      if (!parent) {
          console.error("Parent node not found during branching");
          setIsProcessing(false);
          return;
      }

      const newNode: ProjectNode = {
        id: targetNodeId, parentId: project.currentNodeId, timestamp, userInput: finalInput, userAttachments: currentAttachments, chat: [],
        data: { 
          summary: subMode === 'cleanup' ? "Consolidating history..." : "Initializing...", 
          keyPoints: [], 
          projectKnowledge: parent.data?.projectKnowledge || {}, 
          projectData: parent.data?.projectData || { stores: [] } 
        },
        visualization: { title: subMode === 'cleanup' ? "Consolidated State" : "New Branch", widgets: [] }, 
        children: [], 
        isLoading: true, 
        processingStage: 'analyzing'
      };

      const safeChildren = parent.children || [];

      updatedProject = { 
          ...project, 
          nodes: { 
              ...project.nodes, 
              [project.currentNodeId]: { ...parent, children: [...safeChildren, targetNodeId] }, 
              [targetNodeId]: newNode 
          }, 
          currentNodeId: targetNodeId 
      };
    }
    setProject(updatedProject);

    try {
      const apiCall = generateNodeResponse(targetNodeId, updatedProject, subMode, updatedProject.selectedModel, updatedProject.thinkingBudget, updatedProject.isGroundingEnabled, (stage) => {
              setProject(curr => ({ ...curr, nodes: { ...curr.nodes, [targetNodeId]: { ...curr.nodes[targetNodeId], processingStage: stage } } }));
      }, controller.signal);
      const response = await Promise.race([apiCall, new Promise<never>((_, rej) => setTimeout(() => rej(new Error("Timeout")), 180000))]);

      setProject(current => {
          const node = current.nodes[targetNodeId];
          let chat = [...(node.chat || [])];
          let updatedUserInput = node.userInput;
          if (subMode === 'cleanup') { 
              if (response.consolidatedUserIntent) updatedUserInput = response.consolidatedUserIntent; 
              chat = [{ role: 'assistant', text: response.chatReply, timestamp: Date.now(), groundingSources: response.groundingSources, visualizationSnapshot: response.updatedVisualization, dataSnapshot: response.updatedData }]; 
          }
          else chat.push({ role: 'assistant', text: response.chatReply, timestamp: Date.now(), groundingSources: response.groundingSources, visualizationSnapshot: response.updatedVisualization, dataSnapshot: response.updatedData });
          return { ...current, nodes: { ...current.nodes, [targetNodeId]: { ...node, userInput: updatedUserInput, isLoading: false, processingStage: 'idle', chat, data: response.updatedData, visualization: response.updatedVisualization, restorePoint: undefined, debugInfo: { ...response.debugInfo, response: `Thought Process: ${response.thoughtProcess}\n\n${response.debugInfo?.response || ''}` } } } };
      });
    } catch (err: any) {
      const isAbort = err.message === "Request cancelled by user.";
      setProject(current => { const node = current.nodes[targetNodeId]; const chat = [...(node.chat || [])]; chat.push({ role: 'assistant', text: isAbort ? '⛔ Request cancelled.' : `⚠️ Error: ${err.message}`, timestamp: Date.now() }); return { ...current, nodes: { ...current.nodes, [targetNodeId]: { ...node, chat, isLoading: false, processingStage: 'idle' } } }; });
    } finally { abortControllerRef.current = null; setIsProcessing(false); }
  };

  const handlePaste = async (e: React.ClipboardEvent) => {
    const items = e.clipboardData.items;
    const newAtts: {name: string, type: string, data: string}[] = [];
    for (let i = 0; i < items.length; i++) { if (items[i].type.indexOf('image') !== -1) { const file = items[i].getAsFile(); if (file) { const dataUrl = await new Promise<string>((res) => { const reader = new FileReader(); reader.onload = () => res(reader.result as string); reader.readAsDataURL(file); }); newAtts.push({ name: `pasted-${Date.now()}-${i}`, type: file.type, data: dataUrl }); } } }
    if (newAtts.length > 0) setAttachments(prev => [...prev, ...newAtts]);
  };

  return (
    <div className="flex h-screen bg-white text-slate-900 overflow-hidden">
      <ConfirmationModal isOpen={!!confirmDelete} onConfirm={() => confirmDelete && setProject(prev => { const newNodes = { ...prev.nodes }; const nodeToDelete = newNodes[confirmDelete.id]; if (!nodeToDelete) return prev; if (nodeToDelete.parentId && newNodes[nodeToDelete.parentId]) { const parent = newNodes[nodeToDelete.parentId]; newNodes[nodeToDelete.parentId] = { ...parent, children: (parent.children || []).filter(cid => cid !== confirmDelete.id) }; } const collect = (tid: string): string[] => { const n = newNodes[tid]; if (!n) return []; let desc = [tid]; (n.children || []).forEach(cid => { desc = [...desc, ...collect(cid)]; }); return desc; }; const ids = collect(confirmDelete.id); ids.forEach(tid => { delete newNodes[tid]; }); let nextId = prev.currentNodeId; if (ids.includes(prev.currentNodeId)) nextId = nodeToDelete.parentId && newNodes[nodeToDelete.parentId] ? nodeToDelete.parentId : prev.rootId; return { ...prev, nodes: newNodes, currentNodeId: nextId }; })} onCancel={() => setConfirmDelete(null)} title="Delete Branch" message="This action cannot be undone." />
      <ConfirmationModal isOpen={!!widgetToDelete} onConfirm={() => setProject(prev => { const node = prev.nodes[widgetToDelete!.nodeId]; if (!node || !node.visualization?.widgets) return prev; const newWidgets = [...node.visualization.widgets]; newWidgets.splice(widgetToDelete!.idx, 1); return { ...prev, nodes: { ...prev.nodes, [widgetToDelete!.nodeId]: { ...node, visualization: { ...node.visualization, widgets: newWidgets } } } }; })} onCancel={() => setWidgetToDelete(null)} title="Delete Widget" message="Remove from history?" />

      <div className={`transition-all duration-300 ease-in-out border-r border-slate-200 bg-white flex shrink-0 ${isSidebarOpen ? 'w-64' : 'w-0'}`} style={{ overflow: isSidebarOpen ? 'visible' : 'hidden' }}>
        <Sidebar nodes={project.nodes} rootId={project.rootId} currentNodeId={project.currentNodeId} onSelectNode={(id) => { setProject(prev => ({ ...prev, currentNodeId: id })); setEditingNodeId(null); }} onDeleteNode={(id) => { if (id !== project.rootId) setConfirmDelete({ id }); }} onImport={setProject} onModelChange={(m) => setProject(prev => ({ ...prev, selectedModel: m }))} onBudgetChange={(l) => setProject(prev => ({ ...prev, thinkingBudget: l }))} onGroundingToggle={(e) => setProject(prev => ({ ...prev, isGroundingEnabled: e }))} onProviderChange={(p) => setProject(prev => ({ ...prev, modelProvider: p }))} onCustomConfigChange={(c) => setProject(prev => ({ ...prev, customModelConfig: { ...prev.customModelConfig, ...c } }))} projectState={project} onToggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} isOpen={isSidebarOpen} />
      </div>

      <main className="flex-1 flex flex-col relative min-w-0 bg-white">
        <NodeView node={currentNode} parentNode={parentNode} projectState={project} onSelectNode={(id) => { setProject(prev => ({ ...prev, currentNodeId: id })); setEditingNodeId(null); }} onRegenerate={(txt) => { setInput(txt); setEditingNodeId(currentNode.id); }} onSynthesize={(topic) => handleSubmit(topic, 'synthesize')} onRefresh={() => handleSubmit(undefined, 'refresh')} onMindmapNodeClick={(n) => handleSubmit(`Expand: ${n.label}`, 'branch')} onDeleteChatMessage={(i) => setProject(prev => { const node = prev.nodes[prev.currentNodeId]; if (!node?.chat) return prev; const newChat = [...node.chat]; newChat.splice(i, 1); return { ...prev, nodes: { ...prev.nodes, [prev.currentNodeId]: { ...node, chat: newChat } } } }; })} onDeleteWidget={(nodeId, idx) => setWidgetToDelete({ nodeId, idx })} onToggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} isSidebarOpen={isSidebarOpen} onUpdateNodeData={(nid, data) => setProject(prev => { const node = prev.nodes[nid]; if (!node) return prev; return { ...prev, nodes: { ...prev.nodes, [nid]: { ...node, data: { ...node.data, ...data } } } }; })} onRevertState={(i) => setProject(prev => { const node = prev.nodes[prev.currentNodeId]; if (!node?.chat[i]?.dataSnapshot) return prev; const target = node.chat[i]; return { ...prev, nodes: { ...prev.nodes, [prev.currentNodeId]: { ...node, chat: node.chat.slice(0, i + 1), data: JSON.parse(JSON.stringify(target.dataSnapshot)), visualization: JSON.parse(JSON.stringify(target.visualizationSnapshot)), isLoading: false, processingStage: 'idle' } } }; })} onShowCleanupModal={() => setShowCleanupModal(true)} onUndoCleanup={() => setProject(prev => { const node = prev.nodes[prev.currentNodeId]; if (!node?.restorePoint) return prev; return { ...prev, nodes: { ...prev.nodes, [node.id]: { ...node, chat: node.restorePoint.chat, data: node.restorePoint.data, visualization: node.restorePoint.visualization, userInput: node.restorePoint.userInput, restorePoint: undefined } } }; })} />
        <ChatInput input={input} setInput={setInput} attachments={attachments} setAttachments={setAttachments} isProcessing={isProcessing} onSubmit={handleSubmit} onStop={() => abortControllerRef.current?.abort()} editingNodeId={editingNodeId} onPaste={handlePaste} />
      </main>

      <CleanupModal 
        isOpen={showCleanupModal}
        onConfirm={(focus) => { setShowCleanupModal(false); handleSubmit(focus, 'cleanup'); }}
        onCancel={() => setShowCleanupModal(false)}
      />
    </div>
  );
};

export default App;

import React, { useState } from 'react';

interface CleanupModalProps {
  isOpen: boolean;
  onConfirm: (focus: string) => void;
  onCancel: () => void;
}

export const CleanupModal: React.FC<CleanupModalProps> = ({ isOpen, onConfirm, onCancel }) => {
  const [focus, setFocus] = useState('');

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200" onClick={onCancel}>
      <div className="bg-white rounded-2xl shadow-2xl max-w-md w-full p-6 animate-in zoom-in-95 duration-200" onClick={e => e.stopPropagation()}>
        <div className="flex items-center gap-3 mb-5">
            <div className="p-2.5 bg-purple-100 text-purple-600 rounded-xl">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z" /></svg>
            </div>
            <div>
                <h3 className="text-lg font-bold text-slate-900">Cleanup & Consolidate</h3>
                <p className="text-xs text-slate-500 font-medium">Compress history into a single master state.</p>
            </div>
        </div>

        <div className="space-y-4">
            <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Focus Instruction (Optional)</label>
                <input 
                    type="text" 
                    value={focus}
                    onChange={(e) => setFocus(e.target.value)}
                    placeholder="E.g., Keep the timeline, discard the brainstorming..."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-purple-500/20 focus:border-purple-500 transition-all placeholder:text-slate-400"
                    autoFocus
                    onKeyDown={(e) => {
                        if (e.key === 'Enter') {
                            onConfirm(focus);
                        }
                    }}
                />
            </div>

            <div className="pt-2 flex flex-col gap-2.5">
                <button 
                    onClick={() => onConfirm(focus)}
                    className="w-full py-3 bg-purple-600 hover:bg-purple-700 text-white rounded-xl font-bold text-sm shadow-md shadow-purple-200 transition-all"
                >
                    Consolidate History
                </button>
            </div>

            <div className="text-center">
                 <button onClick={onCancel} className="text-xs font-bold text-slate-400 hover:text-slate-600 transition-colors">Cancel</button>
            </div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { format } from 'date-fns';
import { ProjectNode } from '../../types';

interface NodeHeaderProps {
  node: ProjectNode;
  parentNode?: ProjectNode;
  allNodes: ProjectNode[];
  currentIndex: number;
  isSidebarOpen: boolean;
  onToggleSidebar: () => void;
  onSelectNode: (id: string) => void;
  onShowDebug: () => void;
  onShowDataExplorer: () => void;
  onRegenerate: () => void;
  onRefresh: () => void;
  onShowSynthesisModal: () => void;
  onShowCleanupModal: () => void;
  onUndoCleanup?: () => void;
  hasDebugError: boolean;
  activeProjectDataLength: number;
}

export const NodeHeader: React.FC<NodeHeaderProps> = ({
  node,
  parentNode,
  allNodes,
  currentIndex,
  isSidebarOpen,
  onToggleSidebar,
  onSelectNode,
  onShowDebug,
  onShowDataExplorer,
  onRegenerate,
  onRefresh,
  onShowSynthesisModal,
  onShowCleanupModal,
  onUndoCleanup,
  hasDebugError,
  activeProjectDataLength,
}) => {
  const hasPrev = currentIndex > 0;
  const hasNext = currentIndex < allNodes.length - 1;

  return (
    <div className="shrink-0 h-16 bg-white/80 backdrop-blur-md border-b border-slate-200 px-6 flex items-center justify-between z-10">
      <div className="flex items-center gap-4 min-w-0">
        {!isSidebarOpen && (
          <button
            onClick={onToggleSidebar}
            className="p-2 -ml-2 hover:bg-slate-100 rounded-lg text-slate-500 transition-colors border border-transparent hover:border-slate-100"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 6h16M4 12h16M4 18h7" />
            </svg>
          </button>
        )}

        <div className="flex items-center gap-2">
          <button
            disabled={!hasPrev}
            onClick={() => onSelectNode(allNodes[currentIndex - 1].id)}
            className="p-1.5 hover:bg-slate-100 rounded-lg text-slate-400 disabled:opacity-20 transition-colors"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
            </svg>
          </button>
          <button
            disabled={!hasNext}
            onClick={() => onSelectNode(allNodes[currentIndex + 1].id)}
            className="p-1.5 hover:bg-slate-100 rounded-lg text-slate-400 disabled:opacity-20 transition-colors"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" />
            </svg>
          </button>
        </div>

        <div className="min-w-0 border-l border-slate-200 pl-4 ml-2">
          <div className="flex items-center gap-2 text-[9px] font-black text-slate-400 uppercase tracking-widest">
            {parentNode ? (
              <span
                className="cursor-pointer hover:text-indigo-600 truncate max-w-[120px]"
                onClick={() => onSelectNode(parentNode.id)}
              >
                {parentNode.visualization?.title || 'Parent'}
              </span>
            ) : (
              <span>Root</span>
            )}
            <span>/</span>
            <span className="shrink-0">{format(new Date(node.timestamp), 'MMM d, HH:mm')}</span>
          </div>
          <div className="flex items-center gap-2 overflow-hidden">
            <h1 className="text-sm font-bold text-slate-900 leading-none mt-1 truncate max-w-md">
              {node.visualization?.title || 'Untitled Node'}
            </h1>

            {node.debugInfo && (
              <button
                onClick={onShowDebug}
                className={`ml-1 p-1 rounded-full transition-all shrink-0 ${
                  hasDebugError
                    ? 'bg-red-100 text-red-600 hover:bg-red-200 animate-pulse'
                    : 'bg-slate-100 text-slate-400 hover:bg-slate-200 hover:text-slate-600'
                }`}
                title="Debug Inspector"
              >
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" />
                </svg>
              </button>
            )}
          </div>
        </div>
      </div>

      <div className="flex gap-2 shrink-0">
        {activeProjectDataLength > 0 && (
          <button
            onClick={onShowDataExplorer}
            className="px-3 py-1.5 bg-white border border-slate-200 text-slate-600 text-[10px] font-bold rounded-lg hover:border-indigo-300 hover:text-indigo-600 transition-all shadow-sm flex items-center gap-2"
            title="Open Data Store Explorer"
          >
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M4 7v10c0 2.21 3.582 4 8 4s8-1.79 8-4V7M4 7c0 2.21 3.582 4 8 4s8-1.79 8-4M4 7c0-2.21 3.582-4 8-4s8 1.79 8 4m0 5c0 2.21-3.582 4-8 4s-8-1.79-8-4"
              />
            </svg>
            Data
            <span className="bg-slate-100 px-1.5 py-0.5 rounded-full text-[9px] text-slate-500">
              {activeProjectDataLength}
            </span>
          </button>
        )}

        <div className="w-px h-6 bg-slate-200 mx-1 self-center"></div>

        <button
          onClick={onRegenerate}
          className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
          title="Regenerate from input"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z"
            />
          </svg>
        </button>
        <button
          onClick={onRefresh}
          className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
          title="Re-analyze context & update project data"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"
            />
          </svg>
        </button>

        {node.restorePoint && onUndoCleanup ? (
          <button
            onClick={onUndoCleanup}
            className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all flex items-center gap-1.5"
            title="Undo Cleanup (Restore previous state)"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" />
            </svg>
          </button>
        ) : (
          <button
            onClick={(e) => { e.stopPropagation(); onShowCleanupModal(); }}
            className="p-2 text-slate-400 hover:text-purple-600 hover:bg-purple-50 rounded-lg transition-all"
            title="Consolidate chat history into a single turn"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z"
              />
            </svg>
          </button>
        )}

        <div className="w-px h-6 bg-slate-200 mx-1 self-center"></div>
        <button
          onClick={onShowSynthesisModal}
          className="px-3 py-1.5 bg-slate-900 text-white text-[10px] font-bold rounded-lg hover:bg-slate-800 transition-all shadow-sm"
        >
          Synthesize Child
        </button>
      </div>
    </div>
  );
};
